/**
 * Templates for Claude Code skills.
 * Written to `.claude/skills/<skill-name>/SKILL.md` — Claude Code's skill loader
 * only discovers skills that live in their own folder as `SKILL.md`.
 * Generated by m-notes CLI — do not edit manually.
 */

export interface SkillTemplateOpts {
  url: string;
  workspaceId: string;
}

export interface SkillFile {
  /** Relative path within `.claude/skills/`, e.g. `mnotes-store/SKILL.md`. */
  path: string;
  content: string;
}

const GENERATED_HEADER = "<!-- Generated by m-notes CLI. Do not edit manually. -->";

/**
 * Generates skill files for m-notes integration.
 * Returns an array of { path, content } pairs. `path` is relative to
 * `.claude/skills/` and always ends in `SKILL.md` so Claude Code's loader
 * discovers the skill.
 */
export function generateSkillTemplates(opts: SkillTemplateOpts): SkillFile[] {
  return [
    {
      path: "mnotes-store/SKILL.md",
      content: `${GENERATED_HEADER}
---
name: mnotes-store
description: Store a knowledge entry in m-notes. Use when the user says /store or asks to save/store knowledge, decisions, patterns, or context.
---

# Store Knowledge in m-notes

Run the \`mnotes kb store\` CLI command via Bash to save knowledge.

## Command

\`\`\`bash
mnotes kb store --key "<category>/<name>" --content "<markdown content>" [--tags "<tag1>,<tag2>"]
\`\`\`

## Parameters
- **--key**: Use the naming convention \`<category>/<name>\` (e.g., \`arch/database\`, \`decision/auth-provider\`, \`pattern/error-handling\`)
- **--content**: The knowledge to store — be specific and include rationale
- **--tags**: Comma-separated category tags (e.g., \`architecture\` or \`decision,auth\`)

Workspace is resolved automatically from the CLI config. Do not pass \`--workspace-id\`.

## Categories
| Prefix | Use for |
|--------|---------|
| \`arch/\` | Architecture decisions |
| \`pattern/\` | Code patterns and idioms |
| \`bug/\` | Bug investigations and fixes |
| \`dep/\` | Dependency notes |
| \`decision/\` | Product/tech decisions |
| \`context/\` | Project context and domain knowledge |
`,
    },
    {
      path: "mnotes-recall/SKILL.md",
      content: `${GENERATED_HEADER}
---
name: mnotes-recall
description: Recall knowledge from m-notes using semantic search. Use when the user says /recall or asks to find/recall/search knowledge, or needs context about a topic.
---

# Recall Knowledge from m-notes

Run the \`mnotes kb recall\` CLI command via Bash to search stored knowledge.

## Command

\`\`\`bash
mnotes kb recall --query "<natural language query>" [--tags "<tag1>,<tag2>"] [--limit <n>]
\`\`\`

## Parameters
- **--query**: Natural language description of what you are looking for (required)
- **--tags**: Comma-separated tags to filter results
- **--limit**: Maximum number of results to return (default 10, max 50)

Workspace is resolved automatically from the CLI config. Do not pass \`--workspace-id\`.

## Tips
- Be specific in your query for better semantic matching
- Use \`mnotes bulk knowledge-recall --tags "arch/*"\` to recall groups of entries by tag prefix
- Use \`mnotes kb snapshot\` to export all knowledge at once
`,
    },
  ];
}
